int32_t sum_positive(const int32_t *arr, size_t len) {
    int32_t *pos = NULL;
    size_t count = 0;

    for (size_t i = 0; i < len; i++) {
        if (arr[i] > 0) {
            int32_t *tmp = realloc(pos, (count + 1) * sizeof(int32_t));
            if (!tmp) {
                free(pos);
                return 0;
            }
            pos = tmp;
            pos[count++] = arr[i];
        }
    }

    int32_t sum = 0;
    for (size_t i = 0; i < count; i++) {
        sum += pos[i];
    }

    free(pos);
    return sum;
}
