public class Solution {
    public static int sum_positive(List<Integer> input) {
        List<Integer> positives = new ArrayList<>();
        for (int i = 0; i < input.size(); i++) {
            int val = input.get(i);
            if (val > 0) {
                positives.add(val);
            }
        }
        int sum = 0;
        for (int i = 0; i < positives.size(); i++) {
            sum += positives.get(i);
        }
        return sum;
    }
