	defer func() {
		if closeErr := file.Close(); closeErr != nil {
			fmt.Printf("error closing file: %v\n", closeErr)
		}
	}()

	_, err = file.WriteString("Hello from the program!")
	if err != nil {
		return fmt.Errorf("failed to write to file: %w", err)
	}

	return nil
}

func main() {
	err := writeGreeting("output.txt")
	if err != nil {
