#include <stdint.h>
#include <stdlib.h>

typedef struct {
    int32_t *data;
    size_t length;
} Vector;

int32_t sum_positive(Vector input) {
    Vector positives;
    positives.data = NULL;
    positives.length = 0;
    size_t capacity = 0;

    for (size_t i = 0; i < input.length; ++i) {
        if (input.data[i] > 0) {
            if (positives.length == capacity) {
                capacity = capacity == 0 ? 1 : capacity * 2;
                positives.data = (int32_t *)realloc(positives.data, capacity * sizeof(int32_t));
            }
            positives.data[positives.length++] = input.data[i];
        }
    }

    int32_t sum = 0;
    for (size_t i = 0; i < positives.length; ++i) {
        sum += positives.data[i];
    }

    free(positives.data);
    return sum;
}

