#include <stdint.h>
#include <stdlib.h>

typedef struct {
    int32_t *data;
    size_t size;
    size_t capacity;
} Vector;

void vector_init(Vector *v) {
    v->data = NULL;
    v->size = 0;
    v->capacity = 0;
}

void vector_push(Vector *v, int32_t value) {
    if (v->size == v->capacity) {
        size_t newcap = (v->capacity == 0) ? 4 : v->capacity * 2;
        int32_t *newdata = (int32_t *)realloc(v->data, newcap * sizeof(int32_t));
        if (!newdata) exit(1);
        v->data = newdata;
        v->capacity = newcap;
    }
    v->data[v->size++] = value;
}

void vector_free(Vector *v) {
    free(v->data);
    v->data = NULL;
    v->size = 0;
    v->capacity = 0;
}

int32_t sum_positive(Vector *input) {
    Vector positives;
    vector_init(&positives);

    int32_t sum = 0;
    for (size_t i = 0; i < input->size; ++i) {
        int32_t val = input->data[i];
        if (val > 0) {
            vector_push(&positives, val);
            sum += val;
        }
    }

    vector_free(&positives);
    return sum;
}
