int sum_positive(int *vec, int size) {
    int sum = 0;
    int new_vec[size]; // Create a new empty vector
    int new_size = 0;

    for (int i = 0; i < size; i++) {
        if (vec[i] > 0) {
            new_vec[new_size++] = vec[i]; // Add positive numbers to the new vector
        }
    }

    for (int i = 0; i < new_size; i++) {
        sum += new_vec[i]; // Sum the positive numbers
    }

    return sum;
}

